import axios from 'axios';

const BASE_URL = "http://localhost:5000/api/tasks";

// GET all tasks (with optional status filtering)
export const getTasks = async (status) => {
  const url = status && status !== 'all' ? `${BASE_URL}?status=${status}` : BASE_URL;
  const response = await axios.get(url);
  return response.data; // This matches your backend format { success: true, data: [...] }
};

// POST a new task
export const createTask = async (taskData) => {
  const response = await axios.post(BASE_URL, taskData);
  return response.data; // Returns { success: true, data: { new object } }
};

// PUT / Update an existing task
export const updateTask = async (id, taskData) => {
  // MongoDB IDs pass through the URL parameter path
  const response = await axios.put(`${BASE_URL}/${id}`, taskData);
  return response.data; // Returns { success: true, data: { updated object } }
};

// DELETE a task
export const deleteTask = async (id) => {
  const response = await axios.delete(`${BASE_URL}/${id}`);
  return response.data; // Returns { success: true, message: "..." }
};
